			lcp=min(lcp,min(v1[k1].second-w1,v2[k2].second-w2));
			ans+=lcp;
			if(lcp<min(v1[k1].second-w1,v2[k2].second-w2)) break;
			w1+=lcp;w2+=lcp;
			if(w1==v1[k1].second) w1=0,k1++;
			if(w2==v2[k2].second) w2=0,k2++;
		}
		cout<<ans<<'\n';
	}
	return 0;
}
