int main(){
	read(n);
	for(int i=1;i<=n;i++) read(a[i]);
	memset(f,63,sizeof(f));f[0]=0;
	a[++n]=1e9+1;
	read(m);
	for(int i=1;i<=m;i++) read(b[i]);
	sort(b+1,b+m+1);
	for(int i=1;i<=n;i++)
		if(~a[i]){
			int k=lower_bound(f+1,f+n+1,a[i])-f;
			len[i]=k;pre[i]=w[k-1];
			f[k]=a[i];w[k]=i;
		}
		else{
			for(int j=m,now=n;j;j--){
				while(b[j]<=f[now]) now--;
				f[now+1]=b[j];w[now+1]=i;
			}
		}
	int now=n,L=len[n],lst=n;
	while(L){
		if(~a[now]){
			ans[now]=a[now];
			lst=now;
			now=pre[now];
			L--;
		}
		else{
			int p=m;
			while(b[p]>=ans[lst]||used[p]) p--;
			used[p]=1;
			ans[now]=b[p];lst=now;L--;
			if(!L) break;
			p=0;
			for(int i=1;i<now;i++)
				if(~a[i]&&len[i]==L&&a[i]<ans[now]){p=i;break;}
			if(p){now=p;continue;}
			now--;
			while(~a[now]) now--;
		}
	}
	//cerr<<len[n]-1<<'\n';
	for(int i=1;i<n;i++)
		if(ans[i]) cout<<ans[i]<<" \n"[i==n-1];
		else{
			if(~a[i]) cout<<a[i]<<" \n"[i==n-1];
			else{
				int p=m;
				while(used[p]) p--;
				used[p]=1;
				cout<<b[p]<<" \n"[i==n-1];
			}
		}
	return 0;
}


